private void configurarTabla() {
        modelo = new DefaultTableModel(
            new String[]{"ID", "Nombre", "Usuario", "Rol", "Estado"}, 0
        ) {
            public boolean isCellEditable(int r, int c) { return false; }
        };
        jTable1.setModel(modelo);
        jTable1.setRowHeight(26);
        jTable1.setSelectionMode(ListSelectionModel.SINGLE_SELECTION);
        jTable1.getTableHeader().setBackground(new Color(30, 80, 150));
        jTable1.getTableHeader().setForeground(Color.WHITE);
        jTable1.setAutoCreateRowSorter(true);
    }

    public void cargarUsuarios() {
        new SwingWorker<JsonArray, Void>() {
            @Override
            protected JsonArray doInBackground() {
                try {
                    JsonElement r = ApiClient.get("/usuarios");
                    return r.isJsonArray() ? r.getAsJsonArray() : new JsonArray();
                } catch (Exception ex) { return new JsonArray(); }
            }
            @Override
            protected void done() {
                try {
                    modelo.setRowCount(0);
                    for (JsonElement el : get()) {
                        JsonObject u = el.getAsJsonObject();
                        modelo.addRow(new Object[]{
                            u.get("id").getAsInt(),
                            gs(u, "nombre"),
                            gs(u, "usuario"),
                            gs(u, "nombreRol"),
                            ""
                        });
                    }
                } catch (Exception ex) { ex.printStackTrace(); }
            }
        }.execute();
    }
