    private void btnBorrarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnBorrarActionPerformed
        // TODO add your handling code here:
        int row = jTable1.getSelectedRow();
        if (row < 0) { 
            JOptionPane.showMessageDialog(this, "Selecciona un usuario."); 
            return; 
        }
        int    id = (int)    modelo.getValueAt(jTable1.convertRowIndexToModel(row), 0);
        String n  = (String) modelo.getValueAt(jTable1.convertRowIndexToModel(row), 1);
        
        if (JOptionPane.showConfirmDialog(this, "¿Eliminar usuario: " + n + "?",
                "Confirmar", JOptionPane.YES_NO_OPTION) != JOptionPane.YES_OPTION) return;
        new SwingWorker<Void, Void>() {
            String err;
            @Override protected Void doInBackground() {
                try { ApiClient.delete("/usuarios/" + id); }
                catch (Exception ex) { err = ex.getMessage(); }
                return null;
            }
            @Override protected void done() {
                if (err != null) JOptionPane.showMessageDialog(UsuariosPanel.this, "Error: " + err);
                else { JOptionPane.showMessageDialog(UsuariosPanel.this, "Usuario eliminado."); cargarUsuarios(); }
            }
        }.execute();
    }//GEN-LAST:event_btnBorrarActionPerformed

    private void btnEditarActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnEditarActionPerformed
        // TODO add your handling code here:
        int row = jTable1.getSelectedRow();
        if (row < 0) { JOptionPane.showMessageDialog(this, "Selecciona un usuario."); return; }
        int id = (int) modelo.getValueAt(jTable1.convertRowIndexToModel(row), 0);
        UsuarioFormDialog d = new UsuarioFormDialog(
            (Frame) SwingUtilities.getWindowAncestor(this), true, id);
        d.setVisible(true);
        if (d.isGuardado()) cargarUsuarios();
    }//GEN-LAST:event_btnEditarActionPerformed

    private void btnNuevoActionPerformed(java.awt.event.ActionEvent evt) {//GEN-FIRST:event_btnNuevoActionPerformed
        // TODO add your handling code here:
        UsuarioFormDialog d = new UsuarioFormDialog(
            (Frame) SwingUtilities.getWindowAncestor(this), true, null);
        d.setVisible(true);
        if (d.isGuardado()) cargarUsuarios();
    }//GEN-LAST:event_btnNuevoActionPerformed

    private String gs(JsonObject o, String k) {
        return (o.has(k) && !o.get(k).isJsonNull()) ? o.get(k).getAsString() : "";
    }

